// VALIDACIÓN DE FORMATO DE ENTRADA - subflujo-crea-cita
const input = $input.first().json;

// Extraer datos
const fecha_cita = input.fecha_cita;
const hora_cita = input.hora_cita;
const nombre_cliente = input.nombre_cliente;
const apellido_cliente = input.apellido_cliente;
const modelo_vehiculo = input.modelo_vehiculo;
const patente_vehiculo = input.patente_vehiculo;
const taller_solicitado = input.taller_solicitado;
const servicio_solicitado = input.servicio_solicitado;
const trabajos_extra = input.observaciones_cliente;
const telefono = input.telefono;

// VALIDACIONES
const errores = [];

// 1. VALIDAR FECHA (YYYY-MM-DD)
const regexFecha = /^\d{4}-\d{2}-\d{2}$/;
if (!fecha_cita || !regexFecha.test(fecha_cita)) {
  errores.push(`Fecha inválida: "${fecha_cita}". Formato requerido: YYYY-MM-DD (ej: 2025-04-30)`);
}

// VALIDAR DÍA DE SEMANA
if (fecha_cita && regexFecha.test(fecha_cita)) {
  const [anio, mes, dia] = fecha_cita.split('-').map(Number);
  const fechaObj = new Date(anio, mes - 1, dia);
  const diaSemana = fechaObj.getDay();

  if (diaSemana === 0) {
    errores.push(`La fecha ${fecha_cita} es domingo. El taller no recibe vehículos los fines de semana (lunes a viernes únicamente).`);
  } else if (diaSemana === 6) {
    errores.push(`La fecha ${fecha_cita} es sábado. El taller no recibe vehículos los fines de semana (lunes a viernes únicamente).`);
  }

  // VALIDAR FERIADOS NACIONALES
  const feriados = [
    "2026-01-01","2026-02-16","2026-02-17","2026-03-23",
    "2026-03-24","2026-04-02","2026-04-03","2026-05-01",
    "2026-05-25","2026-06-15","2026-06-20","2026-07-09",
    "2026-08-17","2026-10-12","2026-11-20","2026-12-08",
    "2026-12-25"
];

  if (feriados.includes(fecha_cita)) {
    errores.push(`La fecha ${fecha_cita} es feriado nacional. El taller no atiende ese día.`);
  }
}

// VALIDAR ANTICIPACIÓN (no hoy, no pasado) — hora de Argentina, sin importar TZ del VPS
if (fecha_cita && regexFecha.test(fecha_cita)) {
  // "hoy" en Argentina como "YYYY-MM-DD" (en-CA da formato ISO)
  const hoyAR = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Argentina/Salta' });
  if (fecha_cita <= hoyAR) {                       // comparación lexicográfica de ISO = segura
    errores.push(`La fecha ${fecha_cita} no se puede agendar: las citas se piden desde mañana en adelante (mínimo 24 hs de anticipación).`);
  }
}

// VALIDAR VIERNES + REPARACIÓN (reparaciones solo lunes a jueves)
if (fecha_cita && regexFecha.test(fecha_cita) && servicio_solicitado) {
  const [_a, _m, _d] = fecha_cita.split('-').map(Number);
  const _diaNum = new Date(_a, _m - 1, _d).getDay();
  const _esReparacion = /freno|suspens|eléctric|electr|motor|transmis|aire acondicionado|a\/c|reparación|reparacion|reparar/i
    .test(servicio_solicitado);
  if (_diaNum === 5 && _esReparacion) {
    errores.push(`Reparaciones no se atienden los viernes. El taller realiza reparaciones de lunes a jueves únicamente. Servicio solicitado: "${servicio_solicitado}".`);
  }
}

// 2. VALIDAR HORA (HH:MM)
const regexHora = /^\d{2}:\d{2}$/;
if (!hora_cita || !regexHora.test(hora_cita)) {
  errores.push(`Hora inválida: "${hora_cita}". Formato requerido: HH:MM (ej: 10:30)`);
}

const turnosValidos = [
  "08:00", "08:15", "08:30", "08:45",
  "09:00", "09:15", "09:30", "09:45",
  "10:00", "10:15"
];
if (hora_cita && !turnosValidos.includes(hora_cita)) {
  errores.push(`Hora no permitida: "${hora_cita}". Solo se aceptan turnos: ${turnosValidos.join(', ')}`);
}

// 3. NOMBRE Y APELLIDO — opcionales, se defaultean si no vienen
const nombreFinal   = (nombre_cliente   && nombre_cliente.trim().length   >= 2)
  ? nombre_cliente.trim()
