const trabajos_extra = input.observaciones_cliente;
const telefono = input.telefono;
// VALIDACIONES
const errores = [];

// 1. VALIDAR FECHA (YYYY-MM-DD)
const regexFecha = /^\d{4}-\d{2}-\d{2}$/;
if (!fecha_cita || !regexFecha.test(fecha_cita)) {
  errores.push(`Fecha inválida: "${fecha_cita}". Formato requerido: YYYY-MM-DD (ej: 2025-04-30)`);
}

// VALIDAR DÍA DE SEMANA (JavaScript real - 100% confiable)
if (fecha_cita && regexFecha.test(fecha_cita)) {
  // Parsear como fecha local sin desplazamiento de timezone
  const [anio, mes, dia] = fecha_cita.split('-').map(Number);
  const fechaObj = new Date(anio, mes - 1, dia); // mes es 0-indexed
  const diaSemana = fechaObj.getDay(); // 0=domingo, 6=sábado

  if (diaSemana === 0) {
    errores.push(`La fecha ${fecha_cita} es domingo. El taller no recibe vehículos los fines de semana (lunes a viernes únicamente).`);
  } else if (diaSemana === 6) {
    errores.push(`La fecha ${fecha_cita} es sábado. El taller no recibe vehículos los fines de semana (lunes a viernes únicamente).`);
  }

  // VALIDAR FERIADOS NACIONALES
  const feriados = [
    "2025-01-01","2025-02-12","2025-02-13","2025-03-24",
    "2025-04-02","2025-04-18","2025-05-01","2025-05-25",
    "2025-06-20","2025-07-09","2025-08-17","2025-10-12",
    "2025-11-20","2025-12-08","2025-12-25",
    "2026-01-01","2026-03-24","2026-04-02","2026-05-01",
    "2026-05-25","2026-06-20","2026-07-09","2026-08-17",
    "2026-10-12","2026-11-20","2026-12-08","2026-12-25"
  ];

  if (feriados.includes(fecha_cita)) {
    errores.push(`La fecha ${fecha_cita} es feriado nacional. El taller no atiende ese día.`);
  }
}

// 2. VALIDAR HORA (HH:MM)
const regexHora = /^\d{2}:\d{2}$/;
if (!hora_cita || !regexHora.test(hora_cita)) {
  errores.push(`Hora inválida: "${hora_cita}". Formato requerido: HH:MM (ej: 10:30)`);
}

// Validar que sea uno de los turnos válidos (08:00 a 10:15 cada 15 min)
