if (!patenteNormalizada ||
    (!regexPatenteVieja.test(patenteNormalizada) && !regexPatenteNueva.test(patenteNormalizada))) {
  errores.push(`Patente inválida: "${patente_vehiculo}". Formatos aceptados: ABC123 (viejo) o AB123CD (Mercosur)`);
}

// 6. VALIDAR TELÉFONO
const telefonoNormalizado = telefono ? telefono.replace(/[\s\-().]/g, '') : '';
const regexTelefono = /^(\+?549\d{8,10}|0\d{9,10}|15\d{8}|\d{10})$/;
if (!telefono || !regexTelefono.test(telefonoNormalizado)) {
  errores.push(`Teléfono inválido: "${telefono}". Formatos aceptados: +5491123456789, 1123456789, 01123456789`);
}

// 7. NORMALIZAR Y VALIDAR TALLER
const tallerMap = {
  "nissan - tucuman": "Nissan - Tucuman",
  "nissan - tucumán": "Nissan - Tucuman",
  "tucuman": "Nissan - Tucuman",
  "tucumán": "Nissan - Tucuman",
  "nissan - santiago del estero": "Nissan - Santiago del Estero",
  "santiago del estero": "Nissan - Santiago del Estero",
  "santiago": "Nissan - Santiago del Estero"
};

const tallerNormalizado = taller_solicitado
  ? (tallerMap[taller_solicitado.toLowerCase().trim()] || taller_solicitado)
  : null;

const talleresValidos = [
  "Nissan - Tucuman",
  "Nissan - Santiago del Estero"
];

if (!tallerNormalizado || !talleresValidos.includes(tallerNormalizado)) {
  errores.push(`Taller inválido: "${taller_solicitado}". Valores permitidos: "${talleresValidos[0]}" o "${talleresValidos[1]}"`);
}

// 8. VALIDAR SERVICIO
if (!servicio_solicitado || servicio_solicitado.trim().length < 2) {
  errores.push(`Servicio solicitado inválido: "${servicio_solicitado}". Debe especificarse el servicio`);
}

// SI HAY ERRORES: retornar error
if (errores.length > 0) {
  return [{
    json: {
      success: false,
      error: "VALIDACIÓN_FORMATO_FALLIDA",
      errores: errores,
      datos_recibidos: {
        fecha_cita,
        hora_cita,
        nombre_cliente,
        apellido_cliente,
        modelo_vehiculo,
        patente_vehiculo,
        taller_solicitado,
        servicio_solicitado,
        trabajos_extra,
        telefono
      }
    }
  }];
}

