    nombre_cliente:    nombreFinal,
    apellido_cliente:  apellidoFinal,
    modelo_vehiculo:   modelo_vehiculo.trim(),
    patente_vehiculo:  patenteNormalizada,
    taller_solicitado: tallerNormalizado,
    servicio_solicitado,
    trabajos_extra,
    telefono:          telefonoNormalizado,
  }
}];
